---region currency
function LSdkCpMadFun:_GetCurrencyParams()
    --港币 HKD，符号：HK$
    --台币TWD ，符号：NT$
    --澳门MOP， 符号：MOP$
    --美元USD， 符号：$

    --local locale = self._locale
    --if string.startswith(locale, "zhtw") then
    --    return "NT$","TWD"
    --elseif string.startswith(locale, "zhhk") then
    --    return "HK$","HKD"
    ----elseif string.startswith(locale, "zhmo") then
    ----    return "MOP$","MOP"
    --end

    local province = self._sProvince or ""
    local country = self._sCountry or ""
    local city = self._sCity or ""

    if string.isempty(province) then
        return "NT$","TWD"
    end

    local s, e
    s,e = string.find(province, "台湾")
    if s then
        return "NT$","TWD"
    end
    s,e = string.find(province, "香港")
    if s then
        return "HK$","HKD"
    end

    s,e = string.find(province, "澳门")
    if s then
        return "$","USD"
    end

    return "NT$","TWD"
end

function LSdkCpMadFun:_InitCurrency()
