function LSdkCpMadFun:GetSurveyData()
    if not self._surveyList then return end
    local time = GetTimestamp()
    for k,v in ipairs(self._surveyList) do
        if v.endTime > time then
            if v.surveyId == "278972121" then
                if gModelInstance and gModelInstance:IsBattleNodePass(10070) then
                    return v
                end
            elseif v.surveyId == "278970643" then
                if gModelInstance and gModelInstance:IsBattleNodePass(40200) then
                    return v
                end
            elseif v.surveyId == "278971065" then
                if gModelPlayer and gModelPlayer:GetCreateDay() >= 3 then
                    return v
                end
            elseif v.surveyId == "278986466" then
                if gModelPlayer and gModelPlayer:GetPlayerLv() >= 40 then
                    local timestamp = GetTimestamp()
                    if timestamp >= 1726329600 then
                        return v
                    end
                end
            elseif v.surveyId == "274594067" then
                if gModelPlayer and gModelPlayer:GetCreateDay() >= 3 then
                    return v
                end
            else
                return v
            end
        end
    end
    return nil
end

function LSdkCpMadFun:QuerySurveyList()
    if self._isNotSupportSurvey then return end

    local platformId = self._sPlatformId
    local serverId = gLGameLogin:GetServerId()
    local roleId = gModelPlayer:GetPlayerId() or ""
    local ext = ""
    local ext1 = ""
    local ext2 = ""
    local timestamp = GetTimestamp()
    local lng = "zh-TW"
    local notifyUrl = (gLGameLogin:GetServicesUrl() or "") .. "/baiao/questionnaireCallBack.do"

    local properties = self:_InternalGetProperties()
    local coChannelId = properties.cochannelId or ""
    local appCode = ""

    self:_InternalStopWebQuestionnaire()

    local webReq = LCpWebReq:New()
    self._questionnaireWebReq = webReq

    local gameId = self:GetGameId() or "0"
    local extFmtStr = "{\"gameId\":%s,\"loginDate\":%s,\"level\":%s,\"roleId\":%s,\"serverId\":%s,\"coChannelId\":%s,\"chargeMoney\":%s,\"registerData\":%s}"
    local loginDate = getInt(self._loginTime or 0)
    local level = gModelPlayer:GetPlayerLv() or 0
    local chargeMoney = gModelPlayer.chargeMoney or 0
    local registerData = getInt(gModelPlayer:GetRegTime() or 0)
    ext1 = string.format(extFmtStr, gameId, loginDate, level, roleId, serverId, coChannelId, chargeMoney, registerData)

    local sessionId = roleId..ext..ext1..ext2..timestamp..notifyUrl
    local sign = CS.md5FromString(sessionId..LGameLogin.AuthKey)
    local tokenTbl = {
        "roleId="..roleId,
        "ext="..ext,
        "ext1="..ext1,
        "ext2="..ext2,
        "timestamp="..timestamp,
        "notifyUrl="..notifyUrl,
        "sign="..sign
    }
    local paramPart = table.concat(tokenTbl, "&")
    local params = "/baiao/questionnaireverify.do?"..paramPart

    local urlList = gLGameLogin:GetServicesUrlList()
    webReq:StartReq(urlList, params, function (ret, result)
        if ret ~= CS.YXWebRet.ok then
            self:_InternalStopWebQuestionnaire()
        else
            local code = tostring(result.code)
            if(code ~= "0") then
                self:_InternalStopWebQuestionnaire()
            else
                local data = result.data
                sign = data.sign or ""
                appCode = data.id or ""
                timestamp = data.timestamp or ""
                self._impl:SendCpNativeMessage("QuerySurveyList", platformId, serverId, roleId, ext, ext1, ext2, timestamp, lng, notifyUrl, sign, coChannelId, appCode)
            end
        end
    end,false)
end

