--on cp message
function LSdkCpMadFun:OnLoginResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        self._sUserId = args[2]
        self._sToken = args[3]
        self._sPlatformId = args[4]
        self._sCountry = args[5]
        self._sProvince = args[6]
        self._sCity = args[7]
        LNativeHelper.SetReportUserId(self._sUserId)
        self:_InternalStartWebValidUser()
        self:GetUserInfo()
        self:InitFcmToken()
        --self:SetDelAccountUrl()
    else
        self._sUserId = ""
        self._sToken = ""
        self._sPlatformId = ""

        self:LoginFailure()
    end
end

function LSdkCpMadFun:_InternalStopWebValidUser()
    if self._webReq then
        self._webReq:Destroy()
        self._webReq = nil
    end
end

function LSdkCpMadFun:_InternalStartWebValidUser()
    if string.isempty(self._sToken) then return end
    self._isValidUser = false
    local webReq = self._webReq
    if webReq and not webReq:IsDestroy() then
        if webReq:IsSameValidReqParam(self._sToken) then -- 同样的验证码
            if not webReq:IsFinished() or webReq:IsOK() then
                --正在请求或者，已经请求成功了获得了结果，不再请求
                return
            end
        end
    end

    self:_InternalStopWebValidUser()

    webReq = LCpWebReq:New()
    self._webReq = webReq

    webReq:SetValidReqParam(self._sToken)

    local sessionId = self._sToken or ""
    local sign = string.upper(CS.md5FromString(sessionId..LGameLogin.AuthKey))
    local tokenTbl = {
        "sessionId="..sessionId,
        "sign="..sign
    }
    local paramPart = table.concat(tokenTbl, "&")
    local params = "baiao/loginverify.do?"..paramPart

    local urlList = gLGameLogin:GetServicesUrlList()

    webReq:StartReq(urlList, params, function (ret, result)
        if ret ~= CS.YXWebRet.ok then
            GF.ShowMessage(ccClientText(140))
            LogError("AuthCodeError ...")
            self:_InternalStopWebValidUser() --销毁可以进行下次验证
            self:LoginFailure()
        else
            local code = tostring(result.code)
            if(code == "1") then
                local data = result.data
                local sOneId = tostring(data["oneId"])
                local sPlatformId = data["platformId"]
                local sUserId = data["userId"]
                local sUserName = data["userName"]
                local sNickName = data["nickName"]
                self._isValidUser = true
                self:LoginOk()
            else
                GF.ShowMessage(ccClientText(140))
                LogError("error AuthCode response code = "..tostring(code).."|"..tostring(result.data))
                self:_InternalStopWebValidUser() --销毁可以进行下次验证
                self:LoginFailure()
            end
        end
    end,true)
end

function LSdkCpMadFun:OnLogoutResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        local sUserId = args[2]
        if sUserId == self._sUserId then
