function LSdkCpMadFun:OnQuerySurveyListResult(args)
    self._surveyList = nil
    local code = tostring(args[1])
    if code == "0" then
        local listTbl = JSON.decode(args[2])
        self._surveyList = listTbl

        local zoneoffset = 28800
        local year,month,day,hour, min, sec, timestamp
        --{"deliverId":20091,"surveyId":"10031","surveyName":"1212121212","deliverStatus":1,"startTime":"2023-03-15 09:36:44","endTime":"2023-03-31 09:37:44","rank":null,"linkUrl":"","token":""},{"deliverId":20092,"surveyId":"10028","surveyName":"333333","deliverStatus":1,"startTime":"2023-03-15 10:08:07","endTime":"2023-03-31 10:09:07","rank":null,"linkUrl":"","token":""}
        for k,v in ipairs(listTbl) do
            year,month,day,hour, min, sec = string.match(v.startTime, "(%d+)-(%d+)-(%d+) (%d+):(%d+):(%d+)")
            timestamp = LUtil.GetTime({year=year, month=month,day=day,hour=hour,min=min,sec=sec})
            v.startTime = timestamp - zoneoffset
            year,month,day,hour, min, sec = string.match(v.endTime, "(%d+)-(%d+)-(%d+) (%d+):(%d+):(%d+)")
            timestamp = LUtil.GetTime({year=year, month=month,day=day,hour=hour,min=min,sec=sec})
            v.endTime = timestamp - zoneoffset

            v.rank = checknumber(v.rank)
        end

        table.sort(listTbl, function(a, b)
            return a.rank < b.rank
        end)
    else
        if LOG_INFO_ENABLED then
            print("QuerySurveyResult,  code=" ..code ..", msg = ".. tostring(args[2]))
        end
    end
    FireEvent(EventNames.QUERY_SURVEY_LIST_RESULT)
end

function LSdkCpMadFun:OnSurveyViewClosed(args)
    FireEvent(EventNames.SURVEY_VIEW_CLOSED)
    self:QuerySurveyList()
end

